UPDATE public.questions SET
  stimulus_text = 'The debate over the merits of social media has been a contentious one for years.  While some individuals maintain that platforms such as Facebook and Twitter provide opportunities for connection and community building, others argue that these platforms are harmful, contributing to the spread of misinformation and promoting a culture of negativity.  However, there is a growing consensus among scholars that the most significant effect of social media is its impact on mental health.  A recent study found that users who spend more time on social media platforms experience higher levels of anxiety and depression, regardless of the content they engage with.  This finding suggests that',
  question_text = 'Which choice completes the sentence with the most logical and precise word or phrase?',
